+const INVALID_NL_CATD: nl_catd = -1;
+const CATGETS_MAGIC: u32 = 0x9604_08de;
+const CATALOG_HEADER_WORDS: usize = 3;
+const CATALOG_SLOT_WORDS: usize = 3;
